import random

def print_board(board):
    for row in board:
        print(" | ".join(row))
        print("-" * 5)

def check_winner(board, player):
    # Check rows, columns, and diagonals
    for row in board:
        if all([spot == player for spot in row]):
            return True
    for col in range(3):
        if all([board[row][col] == player for row in range(3)]):
            return True
    if all([board[i][i] == player for i in range(3)]) or all([board[i][2 - i] == player for i in range(3)]):
        return True
    return False

def is_full(board):
    return all([spot != " " for row in board for spot in row])

def get_move(board, player):
    if player == "X":
        computer_choice = random.choice([(i, j) for i in range(3) for j in range(3) if board[i][j] == " "])
        board[computer_choice[0]][computer_choice[1]] = "X"
    else:
        row, col = input("Enter your move (row col): ").split()
        board[int(row)][int(col)] = "O"

def tic_tac_toe():
    board = [[" " for _ in range(3)] for _ in range(3)]
    current_player = "O"
    while True:
        print_board(board)
        get_move(board, current_player)
        if check_winner(board, current_player):
            print_board(board)
            print(f"Player {current_player} wins!")
            break
        if is_full(board):
            print_board(board)
            print("It's a tie!")
            break
        current_player = "X" if current_player == "O" else "O"

tic_tac_toe()
```

