```cpp
#include <iostream>
#include <unistd.h>
#include <stdio.h>
#include <sys/types.h>
#include <sys/wait.h>

int main() {
    int fd[2]; // File descriptors for pipe
    pipe(fd);  // Create the pipe

    pid_t pid = fork(); // Create a new process

    if (pid == -1) {
        // Error forking
        perror("fork");
        return 1;
    } else if (pid == 0) { // Child process
        // Close the read end of the pipe
        close(fd[0]);

        // Redirect stdin and stdout to the write end of the pipe
        dup2(fd[1], STDIN_FILENO);
        dup2(fd[1], STDOUT_FILENO);

        // Close the write end of the pipe
        close(fd[1]);

        // Simulate some output
        std::cout << "Hello from child process!" << std::endl;

        // Exit child process
        _exit(0);
    } else { // Parent process
        // Close the write end of the pipe
        close(fd[1]);

        // Read from the read end of the pipe
        char buffer[256];
        std::cout << "Parent process reading: ";
        std::cin.getline(buffer, sizeof(buffer)); // Normally, you'd use read() or fgets() here

        // Wait for child to finish
        wait(NULL);

        // Exit parent process
        return 0;
    }
}
```

In this example:
1. A pipe is created using `pipe(fd)`.
2. The `fork()` function is called to create a new process.
3. In the child process, the read end of the pipe is closed, and both the standard input and output are redirected to the write end of the pipe using `dup2()`.
4. The child process writes to the pipe, simulating some output.
5. In the parent process, the write end of the pipe is closed, and the read end is used to read from the pipe.
6. The parent waits for the child to finish using `wait(NULL)`.

